def _collect_pixels(raster_data: bytes, width: int, height: int, sample_limit: int) -> list[tuple[int, int, int]]:
    pixels: list[tuple[int, int, int]] = []
    for row in range(height):
        row_offset = row * width * 3
        for col in range(width):
            index = row_offset + col * 3
            pixels.append(
                (
                    raster_data[index],
                    raster_data[index + 1],
                    raster_data[index + 2],
                )
            )
    if len(pixels) <= sample_limit:
        return pixels
    random.seed(0)
    return random.sample(pixels, sample_limit)
